889b82ae-e3da-4b58-b7e9-cd861a4962fe	scripting	Tags: scripting, Shell Scripting สำหรับ Security\nHeading: [Shell Scripting สำหรับ Security] Code Example (bash)\nCode:\n#!/bin/bash\n# === Security Log Monitor ===\n# สคริปต์ตรวจสอบ failed login attempts\n\nLOG_FILE="/var/log/auth.log"\nTHRESHOLD=5\n\necho "[*] Checking failed login attempts..."\n\n# นับจำนวน failed attempts ต่อ IP\ngrep "Failed password" $LOG_FILE | \\\n  awk '{print $(NF-3)}' | \\\n  sort | uniq -c | sort -rn | \\\n  while read count ip; do\n    if [ "$count" -ge "$THRESHOLD" ]; then\n      echo "[!] ALERT: $ip has $count failed attempts!"\n    fi\n  done\n\necho "[*] Check complete."	[-0.030425867,0.0064682886,-0.0017360307,0.014761609,0.0019013487,0.001252328,0.044465255,0.024889441,-0.0326743,0.015289649,-0.019579899,-0.021762595,-0.006974699,-0.0143025685,0.027758947,-0.020695584,0.018926248,-0.006005365,0.024906598,-0.012099269,-0.024590433,-0.0019281496,0.02238303,-0.0010302744,-0.018516717,-0.0078401575,-0.02313177,-0.040808298,-0.0034465573,0.02402219,0.036978386,0.018698914,0.061017115,-0.039738003,-0.0042377636,0.01028996,0.008663764,-0.01750156,-0.0062530567,0.011526478,-0.01821224,0.05189721,-0.0005548949,-0.042840052,-0.00017899956,0.0043550567,0.03379072,-0.023984525,0.011242013,-0.017884897,-0.0033995612,-0.012611052,0.064175636,-0.035608415,0.04656401,0.025089104,0.008119399,0.0039086705,-0.04780694,-0.014382043,-0.007130739,-0.00011666383,-0.040497098,0.037529558,0.0032150985,0.03084362,0.0032670083,-0.0056134323,-0.024353337,-0.021832136,0.016273856,0.038037755,-0.01511831,-0.0043118442,-0.057941202,0.041186083,0.052776657,-0.006026938,-0.012440704,-0.015456809,0.013085059,-0.010767417,-0.00706032,0.02465104,0.0016867097,0.0302893,0.013925031,0.035090107,0.05202616,-0.0014785216,0.03569102,-0.008423612,-0.012077842,-0.011122175,-0.0047748233,0.020087805,-0.016839448,-0.033100903,0.008095389,0.0029126909,-0.015360401,-0.014687673,0.018351639,-0.012538465,0.059036583,0.031490188,0.047